  "interactionFlows": [
    {
      "id": "home-quick-wheel",
      "trigger": "home-quick-wheel-button (event open-wheel)",
      "steps": [
        "Index 切换 surface 至 wheel",
        "WheelEngine 用当前 FilterCriteria 生成 wheelCandidates",
        "进入 idle 态等待用户 spin"
      ],
      "expectedState": "wheel.idle，候选池非空"
    },
    {
      "id": "wheel-spin",
      "trigger": "wheel-spin-button (event spin-wheel)",
      "steps": [
        "wheel.idle -> spinning",
        "WheelEngine.spin() 从候选池随机命中一个索引",
        "播放旋转动画 -> wheel.result",
        "展示 wheel-result-name",
        "提供 accept-result / reshuffle / open-share-card"
      ],
      "errorPath": "候选池为空：回退使用全量菜谱库并提示"
    },
    {
      "id": "filter-apply",
      "trigger": "filter-apply-button (event apply-filter)",
      "steps": [
        "收集 filter-mood/time/meal 三个输入",
        "FilterStore.set(mood,time,meal)",
        "返回上一页；首页推荐与转盘候选池即时刷新"
      ],
      "expectedState": "filter.applied"
    },
    {
      "id": "ingredient-manage-and-recommend",
      "trigger": "ingredients-add-button / delete / show-ingredient-recommendations",
      "steps": [
        "add：校验名称非空去重 -> IngredientStore.add -> 刷新列表",
        "delete：IngredientStore.remove -> 刷新列表",
        "recommend：RecommendService.recommendByIngredients(ingredients) -> ingredients-dish-list"
      ],
      "errorPath": "无食材 -> empty-state；无匹配 -> empty-recommendations"
    },
    {
      "id": "record-add",
      "trigger": "records-add-button / home-add-record-button (event open-add-record)",
      "steps": [
        "recordForm.closed -> editing，默认日期=今日、餐别按当前时段",
        "save-record：校验 dishName 非空、rating 1-5 -> RecordStore.add",
        "dismiss -> closed；刷新 records-list 与 calendar"
      ],
      "errorPath": "dishName 为空 -> 阻止保存并提示"
    },
    {
      "id": "share-card-open",
      "trigger": "wheel-share-button / record-share-button (event open-share-card)",
      "steps": [
        "ShareCardBuilder 由当前决策结果/打卡记录构造 ShareCardData",
        "shareCard.closed -> preview，展示 share-card-preview",
        "save-share-card：保存为图片（MVP 走保存反馈/占位实现，文档记录）",
        "close-share-card -> closed"
      ]
    }
  ],
  "testTargets": [
    "home-quick-wheel-button", "home-filter-button", "home-recommend-list",
    "home-empty-recommendations", "home-today-record-status", "home-add-record-button",
    "wheel-spin-button", "wheel-result-name", "wheel-result-accept-button",
    "wheel-result-reshuffle-button", "wheel-share-button",
    "ingredients-input", "ingredients-add-button", "ingredients-list",
    "ingredients-empty-state", "ingredient-delete-button", "ingredients-recommend-button",
    "ingredients-dish-list", "ingredients-empty-recommendations",
    "filter-mood-group", "filter-time-group", "filter-meal-group",
    "filter-apply-button", "filter-reset-button",
    "records-calendar", "records-add-button", "records-list",
    "records-empty-state", "record-share-button",
    "record-form-date-picker", "record-form-meal-group", "record-form-dish-input",
    "record-form-rating", "record-form-save-button", "record-form-cancel-button",
    "share-card-preview", "share-card-save-button", "share-card-close-button"
  ],
  "notes": {
    "headlessPhase": "先实现 Models/DishCatalog/services，不在本轮落地页面布局；页面/组件在视觉对齐阶段实现",
    "noSeededData": "首次启动不预置示例数据，所有用户数据从空状态开始",
    "shareCardSave": "图片导出为可选能力；MVP 提供保存反馈，最终实现以系统保存能力为准"
  }
}

