            this.mood as string,
            (v: string) => { this.mood = (v === '' ? '' : v) as MoodType; })

          this.Group('可用时间', 'filter-time-group', this.timeOptions.map((o: ChipOption<CookTimeType>) => o.value),
            this.timeOptions.map((o: ChipOption<CookTimeType>) => o.label),
            this.time as string,
