import { SvgIcon } from '../common/SvgIcon';
import {
  MoodType, CookTimeType, MealType, FilterCriteria,
  MOOD_LABELS, COOK_TIME_LABELS, MEAL_LABELS, emptyFilter,
} from '../common/Models';
import { filterStore } from '../services/AppServices';

interface ChipOption<T> {
  value: T;
  label: string;
}

@Component
export struct FilterPage {
  onBack: () => void = () => {};

  @State mood: MoodType | '' = '';
  @State time: CookTimeType | '' = '';
  @State meal: MealType | '' = '';

  private moodOptions: ChipOption<MoodType>[] = [
    { value: 'happy', label: MOOD_LABELS.happy },
    { value: 'tired', label: MOOD_LABELS.tired },
    { value: 'spicy', label: MOOD_LABELS.spicy },
    { value: 'light', label: MOOD_LABELS.light },
    { value: 'comfort', label: MOOD_LABELS.comfort },
    { value: 'adventurous', label: MOOD_LABELS.adventurous },
  ];

  private timeOptions: ChipOption<CookTimeType>[] = [
    { value: 'quick', label: COOK_TIME_LABELS.quick },
    { value: 'normal', label: COOK_TIME_LABELS.normal },
    { value: 'weekend', label: COOK_TIME_LABELS.weekend },
  ];

  private mealOptions: ChipOption<MealType>[] = [
    { value: 'breakfast', label: MEAL_LABELS.breakfast },
    { value: 'lunch', label: MEAL_LABELS.lunch },
    { value: 'dinner', label: MEAL_LABELS.dinner },
    { value: 'lateNight', label: MEAL_LABELS.lateNight },
  ];

  aboutToAppear(): void {
    const cur = filterStore.get();
    this.mood = cur.mood;
    this.time = cur.time;
    this.meal = cur.meal;
  }

  build() {
    Column() {
      // header
      Row() {
        Column() {
          SvgIcon({ variant: 'back', iconSize: 22, strokeWidth: 2 })
        }
        .id('filter-back-button')
        .width(40)
        .height(40)
        .borderRadius(12)
        .backgroundColor(Theme.cardBg)
        .border({ width: 1, color: Theme.borderSoft })
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)
        .onClick(() => this.onBack())

        Text('筛选条件')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
          .margin({ left: 12 })
      }
      .width('100%')
      .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 48, bottom: 16 })

      Scroll() {
        Column() {
          this.Group('心情', 'filter-mood-group', this.moodOptions.map((o: ChipOption<MoodType>) => o.value),
            this.moodOptions.map((o: ChipOption<MoodType>) => o.label),
            this.mood as string,
            (v: string) => { this.mood = (v === '' ? '' : v) as MoodType; })

          this.Group('可用时间', 'filter-time-group', this.timeOptions.map((o: ChipOption<CookTimeType>) => o.value),
            this.timeOptions.map((o: ChipOption<CookTimeType>) => o.label),
            this.time as string,
            (v: string) => { this.time = (v === '' ? '' : v) as CookTimeType; })

          this.Group('餐别', 'filter-meal-group', this.mealOptions.map((o: ChipOption<MealType>) => o.value),
            this.mealOptions.map((o: ChipOption<MealType>) => o.label),
            this.meal as string,
            (v: string) => { this.meal = (v === '' ? '' : v) as MealType; })
        }
        .width('100%')
        .alignItems(HorizontalAlign.Start)
        .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, bottom: 120 })
      }
      .layoutWeight(1)
      .scrollBar(BarState.Off)
      .align(Alignment.Top)

      // bottom actions
      Row() {
        Text('重置')
          .id('filter-reset-button')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textSecondary)
          .textAlign(TextAlign.Center)
          .layoutWeight(1)
          .padding({ top: 14, bottom: 14 })
          .borderRadius(Theme.radiusButton)
          .backgroundColor(Theme.cardBg)
          .border({ width: 1, color: Theme.borderDefault })
          .onClick(() => this.reset())

        Text('应用筛选')
          .id('filter-apply-button')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textOnDark)
          .textAlign(TextAlign.Center)
          .layoutWeight(1)
          .padding({ top: 14, bottom: 14 })
          .borderRadius(Theme.radiusButton)
          .linearGradient({
            angle: 135,
            direction: GradientDirection.RightTop,
            colors: [['#FF6B35', 0.0], ['#FF8A5B', 1.0]],
          } as LinearGradient)
          .margin({ left: 12 })
          .onClick(() => this.apply())
      }
      .width('100%')
      .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 12, bottom: 24 })
      .backgroundColor(Theme.pageBg)
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  Group(title: string, groupId: string, values: string[], labels: string[], selected: string,
    onSelect: (v: string) => void) {
    Column() {
      Text(title)
        .fontSize(18)
        .fontWeight(FontWeight.Bold)
        .fontColor(Theme.textPrimary)
        .margin({ bottom: 12 })

      Flex({ wrap: FlexWrap.Wrap }) {
        ForEach(labels, (label: string, idx: number) => {
          Text(label)
            .fontSize(13)
            .fontWeight(FontWeight.Medium)
            .fontColor(selected === values[idx] ? Theme.brandPrimary : Theme.textSecondary)
            .padding({ left: 16, right: 16, top: 9, bottom: 9 })
            .borderRadius(18)
            .backgroundColor(selected === values[idx] ? Theme.brandOrangeSoft : Theme.cardBg)
            .border({
              width: 1,
              color: selected === values[idx] ? Theme.brandPrimary : Theme.borderSoft,
            })
            .margin({ right: 10, bottom: 10 })
            .onClick(() => {
              if (selected === values[idx]) {
                onSelect('');
              } else {
                onSelect(values[idx]);
              }
            })
        }, (label: string, idx: number) => `${groupId}-${label}-${idx}`)
      }
      .id(groupId)
      .width('100%')
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
    .margin({ bottom: 24 })
  }

  private apply(): void {
    const c: FilterCriteria = { mood: this.mood, time: this.time, meal: this.meal };
    filterStore.set(c);
    this.onBack();
  }

  private reset(): void {
    this.mood = '';
    this.time = '';
    this.meal = '';
    filterStore.reset();
  }
}

