                .border({ width: 1, color: this.meal === m ? Theme.brandPrimary : Theme.borderSoft })
                .margin({ right: 10, bottom: 10 })
                .onClick(() => { this.meal = m; })
            }, (m: MealType) => `meal-${m}`)
          }
          .id('record-form-meal-group')
          .width('100%')
          .margin({ bottom: 20 })

