        date: this.date,
        meal: this.meal,
        dishName: name,
        rating: this.rating,
        note: this.note,
      };
      await recordStore.add(input);
    } catch (e) {
      this.errorMsg = '保存失败，请重试';
      return;
    }
    this.onDone();
  }
}

