//
// 分享卡片 (surface: share-card). No HTML artifact yet; implemented in the
// established visual language. Preview card built from ShareCardData +
// save (MVP feedback) / close actions.

import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { ShareCardData } from '../common/Models';
import { promptAction } from '@kit.ArkUI';

@Component
export struct ShareCardPage {
  onClose: () => void = () => {};
  data: ShareCardData | null = null;
  @State saved: boolean = false;

  build() {
    Column() {
      // header
      Row() {
        Column() {
          SvgIcon({ variant: 'back', iconSize: 22, strokeWidth: 2 })
        }
        .id('share-card-close-button')
        .width(40)
        .height(40)
        .borderRadius(12)
        .backgroundColor(Theme.cardBg)
        .border({ width: 1, color: Theme.borderSoft })
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)
        .onClick(() => this.onClose())

        Text('分享卡片')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textPrimary)
          .margin({ left: 12 })
      }
      .width('100%')
      .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, top: 48, bottom: 16 })

      Column() {
        this.PreviewCard()
      }
      .layoutWeight(1)
      .width('100%')
      .justifyContent(FlexAlign.Center)
      .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding })

      // actions
      Row() {
        Text(this.saved ? '已保存' : '保存到相册')
          .id('share-card-save-button')
          .fontSize(15)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.textOnDark)
          .textAlign(TextAlign.Center)
          .layoutWeight(1)
          .padding({ top: 14, bottom: 14 })
          .borderRadius(Theme.radiusButton)
          .linearGradient(this.saved ? BrandGradient.thumbTeal : BrandGradient.brand)
          .onClick(() => this.save())
      }
      .width('100%')
      .padding({ left: Theme.pageHorizontalPadding, right: Theme.pageHorizontalPadding, bottom: 32 })
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  PreviewCard() {
    Column() {
      // hero band
      Column() {
        Text('今天吃这个')
          .fontSize(13)
          .fontColor('rgba(255,255,255,0.72)')
          .margin({ bottom: 8 })
        Text(this.data !== null ? this.data.dishName : '今天吃什么')
          .fontSize(30)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.textOnDark)
          .textAlign(TextAlign.Center)
        if (this.data !== null && this.data.mealLabel.length > 0) {
          Text(this.data.mealLabel)
            .fontSize(13)
            .fontColor('rgba(255,255,255,0.85)')
            .padding({ left: 12, right: 12, top: 5, bottom: 5 })
            .borderRadius(12)
            .backgroundColor('rgba(255,255,255,0.16)')
            .margin({ top: 10 })
        }
      }
      .width('100%')
      .padding({ left: 24, right: 24, top: 32, bottom: 28 })
      .linearGradient(BrandGradient.brand)
      .borderRadius({ topLeft: Theme.radiusHero, topRight: Theme.radiusHero })

      // body
      Column() {
        if (this.data !== null && this.data.tags.length > 0) {
          Flex({ wrap: FlexWrap.Wrap }) {
            ForEach(this.data !== null ? this.data.tags : [], (tag: string) => {
              Text(tag)
                .fontSize(12)
                .fontColor(Theme.brandPrimary)
                .padding({ left: 10, right: 10, top: 4, bottom: 4 })
                .borderRadius(10)
                .backgroundColor(Theme.brandOrangeSoft)
                .margin({ right: 8, bottom: 8 })
            }, (tag: string, idx: number) => `tag-${idx}-${tag}`)
          }
          .width('100%')
          .margin({ bottom: 14 })
        }

        Row() {
          Text('理由')
            .fontSize(13)
            .fontColor(Theme.textTertiary)
            .margin({ right: 8 })
          Text(this.data !== null ? this.data.reason : '随机决定')
            .fontSize(14)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.textPrimary)
            .layoutWeight(1)
        }
        .width('100%')
        .alignItems(VerticalAlign.Top)

        Divider()
          .color(Theme.cardDivider)
          .margin({ top: 16, bottom: 16 })

        Row() {
          Text(this.data !== null ? this.data.dateLabel : '')
            .fontSize(13)
            .fontColor(Theme.textTertiary)
            .layoutWeight(1)
          Text('今天吃什么 · 我的决策')
            .fontSize(12)
            .fontColor(Theme.textQuaternary)
        }
        .width('100%')
      }
      .width('100%')
      .padding({ left: 24, right: 24, top: 20, bottom: 24 })
      .backgroundColor(Theme.cardBg)
      .borderRadius({ bottomLeft: Theme.radiusHero, bottomRight: Theme.radiusHero })
    }
    .id('share-card-preview')
    .width('100%')
    .shadow({ radius: 40, color: 'rgba(255,107,53,0.18)', offsetY: 16 })
  }

  private save(): void {
    if (this.saved) {
      return;
    }
    this.saved = true;
    promptAction.showToast({ message: '已保存到相册', duration: 2000 });
  }
}

